108	    @Override
109	    public ValueDeserializer<Object> unwrappingDeserializer(DeserializationContext ctxt,
110	            NameTransformer transformer)
111	    {
112	        // bit kludgy but we don't want to accidentally change type; sub-classes
113	        // MUST override this method to support unwrapped properties...
114	        if (getClass() != BeanDeserializer.class) {
115	            return this;
116	        }
117	        // 25-Mar-2017, tatu: Not clean at all, but for [databind#383] we do need
118	        //   to keep track of accidental recursion...
119	        if (_currentlyTransforming == transformer) {
120	            return this;
121	        }
122	        _currentlyTransforming = transformer;
123	        try {
124	            UnwrappedPropertyHandler uwHandler = _unwrappedPropertyHandler;
125	            if (uwHandler != null) { // delegate further unwraps, if any
126	                uwHandler = uwHandler.renameAll(ctxt, transformer);
127	            }
128	            PropertyBasedCreator pbCreator = _propertyBasedCreator;
129	            if (pbCreator != null) {
130	                pbCreator = pbCreator.renameAll(ctxt, transformer);
131	            }
132	            // and handle direct unwrapping as well:
133	            return new BeanDeserializer(this, uwHandler, pbCreator,
134	                    _beanProperties.renameAll(ctxt, transformer), true);
135	        } finally { _currentlyTransforming = null; }
136	    }
