183	    /**
184	     * Main deserialization method for bean-based objects (POJOs).
185	     */
186	    @Override
187	    public Object deserialize(JsonParser p, DeserializationContext ctxt) throws JacksonException
188	    {
189	        // common case first
190	        if (p.isExpectedStartObjectToken()) {
191	            if (_vanillaProcessing) {
192	                return _vanillaDeserialize(p, ctxt);
193	            }
194	            // 23-Sep-2015, tatu: This is wrong at some many levels, but for now... it is
195	            //    what it is, including "expected behavior".
196	            p.nextToken();
197	            if (_objectIdReader != null) {
198	                return deserializeWithObjectId(p, ctxt);
199	            }
200	            return deserializeFromObject(p, ctxt);
201	        }
202	        return _deserializeOther(p, ctxt, p.currentToken());
203	    }
204	
205	    protected final Object _deserializeOther(JsonParser p, DeserializationContext ctxt,
206	            JsonToken t) throws JacksonException
207	    {
208	        // and then others, generally requiring use of @JsonCreator
209	        if (t != null) {
210	            switch (t) {
211	            case VALUE_STRING:
212	                return deserializeFromString(p, ctxt);
213	            case VALUE_NUMBER_INT:
214	                return deserializeFromNumber(p, ctxt);
215	            case VALUE_NUMBER_FLOAT:
216	                return deserializeFromDouble(p, ctxt);
217	            case VALUE_EMBEDDED_OBJECT:
218	                return deserializeFromEmbedded(p, ctxt);
219	            case VALUE_TRUE:
220	            case VALUE_FALSE:
221	                return deserializeFromBoolean(p, ctxt);
222	            case VALUE_NULL:
223	                return deserializeFromNull(p, ctxt);
224	            case START_ARRAY:
225	                // these only work if there's a (delegating) creator, or UNWRAP_SINGLE_ARRAY
226	                return _deserializeFromArray(p, ctxt);
227	            case PROPERTY_NAME:
228	            case END_OBJECT: // added to resolve [JACKSON-319], possible related issues
229	                if (_vanillaProcessing) {
230	                    return _vanillaDeserialize(p, ctxt, t);
231	                }
232	                if (_objectIdReader != null) {
233	                    return deserializeWithObjectId(p, ctxt);
234	                }
235	                return deserializeFromObject(p, ctxt);
236	            default:
237	            }
238	        }
239	        return ctxt.handleUnexpectedToken(getValueType(ctxt), p);
240	    }
