409	    private Object _buildRecordFromBuffer(DeserializationContext ctxt,
410	            PropertyBasedCreator creator, PropertyValueBuffer buffer)
411	        throws JacksonException
412	    {
413	        try {
414	            return creator.build(ctxt, buffer);
415	        } catch (Exception e) {
416	            return wrapInstantiationProblem(ctxt, e);
417	        }
418	    }
