426	    /**
427	     * Streamlined version that is only used when no "special"
428	     * features are enabled, and when current logical token
429	     * is {@link JsonToken#START_OBJECT} (or equivalent).
430	     */
431	    private final Object _vanillaDeserialize(JsonParser p, DeserializationContext ctxt)
432	        throws JacksonException
433	    {
434	        final Object bean = _valueInstantiator.createUsingDefault(ctxt);
435	        // [databind#631]: Assign current value, to be accessible by custom serializers
436	        p.assignCurrentValue(bean);
437	
438	        int ix = p.nextNameMatch(_propNameMatcher);
439	        while (ix >= 0) {
440	            p.nextToken();
441	            SettableBeanProperty prop = _propsByIndex[ix];
442	            try {
443	                prop.deserializeAndSet(p, ctxt, bean);
444	            } catch (Exception e) {
445	                wrapAndThrow(e, bean, prop.getName(), ctxt);
446	            }
447	            // Elem #2
448	            ix = p.nextNameMatch(_propNameMatcher);
449	            if (ix < 0) {
450	                break;
451	            }
452	            p.nextToken();
453	            prop = _propsByIndex[ix];
454	            try {
455	                prop.deserializeAndSet(p, ctxt, bean);
456	            } catch (Exception e) {
457	                wrapAndThrow(e, bean, prop.getName(), ctxt);
458	            }
459	            // Elem #3
460	            ix = p.nextNameMatch(_propNameMatcher);
461	            if (ix < 0) {
462	                break;
463	            }
464	            p.nextToken();
465	            prop = _propsByIndex[ix];
466	            try {
467	                prop.deserializeAndSet(p, ctxt, bean);
468	            } catch (Exception e) {
469	                wrapAndThrow(e, bean, prop.getName(), ctxt);
470	            }
471	            // Elem #4
472	            ix = p.nextNameMatch(_propNameMatcher);
473	            if (ix < 0) {
474	                break;
475	            }
476	            p.nextToken();
477	            prop = _propsByIndex[ix];
478	            try {
479	                prop.deserializeAndSet(p, ctxt, bean);
480	            } catch (Exception e) {
481	                wrapAndThrow(e, bean, prop.getName(), ctxt);
482	            }
483	            ix = p.nextNameMatch(_propNameMatcher);
484	        }
485	        if (ix != PropertyNameMatcher.MATCH_END_OBJECT) {
486	            if (ix == PropertyNameMatcher.MATCH_UNKNOWN_NAME) {
487	                return _vanillaDeserializeWithUnknown(p, ctxt, bean,
488	                        p.currentName());
489	            }
490	            return _handleUnexpectedWithin(p, ctxt, bean);
491	        }
492	        return bean;
493	    }
