495	    /**
496	     * Streamlined version that is only used when no "special"
497	     * features are enabled.
498	     */
499	    private final Object _vanillaDeserialize(JsonParser p,
500	    		DeserializationContext ctxt, JsonToken t)
501	        throws JacksonException
502	    {
503	        final Object bean = _valueInstantiator.createUsingDefault(ctxt);
504	        if (t != JsonToken.PROPERTY_NAME) {
505	            return bean;
506	        }
507	        // [databind#631]: Assign current value, to be accessible by custom serializers
508	        // [databind#4184]: but only if we have at least one property
509	        p.assignCurrentValue(bean);
510	        int ix = p.currentNameMatch(_propNameMatcher);
511	        while (ix >= 0) { // minor unrolling here (by-2), less likely on critical path
512	            SettableBeanProperty prop = _propsByIndex[ix];
513	            p.nextToken();
514	            try {
515	                prop.deserializeAndSet(p, ctxt, bean);
516	            } catch (Exception e) {
517	                throw wrapAndThrow(e, bean, prop.getName(), ctxt);
518	            }
519	
520	            // Elem #2
521	            ix = p.nextNameMatch(_propNameMatcher);
522	            if (ix < 0) {
523	                break;
524	            }
525	            prop = _propsByIndex[ix];
526	            p.nextToken();
527	            try {
528	                prop.deserializeAndSet(p, ctxt, bean);
529	            } catch (Exception e) {
530	                throw wrapAndThrow(e, bean, prop.getName(), ctxt);
531	            }
532	            ix = p.nextNameMatch(_propNameMatcher);
533	        }
534	        if (ix != PropertyNameMatcher.MATCH_END_OBJECT) {
535	            if (ix == PropertyNameMatcher.MATCH_UNKNOWN_NAME) {
536	                return _vanillaDeserializeWithUnknown(p, ctxt, bean,
537	                        p.currentName());
538	            }
539	            return _handleUnexpectedWithin(p, ctxt, bean);
540	        }
541	        return bean;
542	    }
