544	    private final Object _vanillaDeserializeWithUnknown(JsonParser p,
545	            DeserializationContext ctxt, Object bean, String propName) throws JacksonException
546	    {
547	        p.nextToken();
548	        handleUnknownVanilla(p, ctxt, bean, propName);
549	
550	        while (true) {
551	            int ix = p.nextNameMatch(_propNameMatcher);
552	            if (ix >= 0) { // normal case
553	                p.nextToken();
554	                try {
555	                    _propsByIndex[ix].deserializeAndSet(p, ctxt, bean);
556	                } catch (Exception e) {
557	                    wrapAndThrow(e, bean, _propsByIndex[ix].getName(), ctxt);
558	                }
559	                continue;
560	            }
561	            if (ix == PropertyNameMatcher.MATCH_END_OBJECT) {
562	                return bean;
563	            }
564	            if (ix != PropertyNameMatcher.MATCH_UNKNOWN_NAME) {
565	                return bean;
566	            }
567	            p.nextToken();
568	            handleUnknownVanilla(p, ctxt, bean, p.currentName());
569	        }
570	    }
