572	    /**
573	     * General version used when handling needs more advanced features.
574	     */
575	    @Override
576	    public Object deserializeFromObject(JsonParser p, DeserializationContext ctxt) throws JacksonException
577	    {
578	        /* 09-Dec-2014, tatu: As per [databind#622], we need to allow Object Id references
579	         *   to come in as JSON Objects as well; but for now assume they will
580	         *   be simple, single-property references, which means that we can
581	         *   recognize them without having to buffer anything.
582	         *   Once again, if we must, we can do more complex handling with buffering,
583	         *   but let's only do that if and when that becomes necessary.
584	         */
585	        if ((_objectIdReader != null) && _objectIdReader.maySerializeAsObject()) {
586	            if (p.hasTokenId(JsonTokenId.ID_PROPERTY_NAME)
587	                    && _objectIdReader.isValidReferencePropertyName(p.currentName(), p)) {
588	                return deserializeFromObjectId(p, ctxt);
589	            }
590	        }
591	        if (_nonStandardCreation) {
592	            if (_unwrappedPropertyHandler != null) {
593	                return deserializeWithUnwrapped(p, ctxt);
594	            }
595	            if (_externalTypeIdHandler != null) {
596	                return deserializeWithExternalTypeId(p, ctxt);
597	            }
598	            Object bean = deserializeFromObjectUsingNonDefault(p, ctxt);
599	            // 27-May-2014, tatu: I don't think view processing would work
600	            //   at this point, so commenting it out; but leaving in place
601	            //   just in case I forgot something fundamental...
602	            /*
603	            if (_needViewProcesing) {
604	                Class<?> view = ctxt.getActiveView();
605	                if (view != null) {
606	                    return deserializeWithView(p, ctxt, bean, view);
607	                }
608	            }
609	            */
610	            return bean;
611	        }
612	        final Object bean = _valueInstantiator.createUsingDefault(ctxt);
613	
614	        // First: do we have native Object Ids (like YAML)?
615	        if (_objectIdReader != null) {
616	            if (p.canReadObjectId()) {
617	                Object id = p.getObjectId();
618	                if (id != null) {
619	                    _handleTypedObjectId(p, ctxt, bean, id);
620	                }
621	            }
622	            // [databind#3838]: since 2.16 Uniform handling of missing objectId
623	            // only for the specific "empty JSON Object" case (and only for non-Native
624	            // Object Ids, see [databind#4607]
625	            else if (p.hasTokenId(JsonTokenId.ID_END_OBJECT)) {
626	                // [databind#4610]: check if we are to skip failure
627	                if (ctxt.isEnabled(DeserializationFeature.FAIL_ON_UNRESOLVED_OBJECT_IDS)) {
628	                    ctxt.reportUnresolvedObjectId(_objectIdReader, bean);
629	                }
630	            }
631	        }
632	        if (_injectables != null) {
633	            injectValues(ctxt, bean);
634	        }
