669	    /**
670	     * Method called to deserialize bean using "property-based creator":
671	     * this means that a non-default constructor or factory method is
672	     * called, and then possibly other setters. The trick is that
673	     * values for creator method need to be buffered, first; and
674	     * due to non-guaranteed ordering possibly some other properties
675	     * as well.
676	     */
677	    @Override
678	    protected Object _deserializeUsingPropertyBased(final JsonParser p, final DeserializationContext ctxt)
679	        throws JacksonException
680	    {
681	        final PropertyBasedCreator creator = _propertyBasedCreator;
682	        PropertyValueBuffer buffer = (_anySetter != null)
683	            ? creator.startBuildingWithAnySetter(p, ctxt, _objectIdReader, _anySetter)
684	            : creator.startBuilding(p, ctxt, _objectIdReader);
685	        TokenBuffer unknown = null;
686	        final Class<?> activeView = _needViewProcesing ? ctxt.getActiveView() : null;
687	        JsonToken t = p.currentToken();
688	        List<BeanReferring> referrings = null;
689	        final boolean isRecord = _beanType.isRecordType();
690	
691	        for (; t == JsonToken.PROPERTY_NAME; t = p.nextToken()) {
692	            String propName = p.currentName();
693	            p.nextToken(); // to point to value
694	            final SettableBeanProperty creatorProp = creator.findCreatorProperty(propName);
695	            // Object Id property?
696	            if (buffer.readIdProperty(propName) && creatorProp == null) {
697	                continue;
698	            }
699	
700	            // Creator property?
701	            if (creatorProp != null) {
702	                if ((activeView != null) && !creatorProp.visibleInView(activeView)) {
703	                    p.skipChildren();
704	                    continue;
705	                }
706	                // [databind#1381]: if useInput=FALSE, skip deserialization from input
707	                if (creatorProp.isInjectionOnly()) {
708	                    // Skip the input value, will be injected later in PropertyValueBuffer
709	                    p.skipChildren();
710	                    continue;
711	                }
712	                // [databind#4629] Need to check for ignored properties for Creator properties since
713	                // Records will have a valid 'creatorProp', so if we don't
714	                // check for ignore first, the ignore configuration will be bypassed.
715	                if (isRecord && IgnorePropertiesUtil.shouldIgnore(propName, _ignorableProps, _includableProps)) {
716	                    handleIgnoredProperty(p, ctxt, handledType(), propName);
717	                    continue;
718	                }
719	                // Last creator property to set?
720	                // [databind#4690] cannot quit early as optimization any more
721	                // if (buffer.assignParameter(creatorProp, value)) { ... build ... }
722	                try {
723	                    buffer.assignParameter(creatorProp,
724	                            _deserializeWithErrorWrapping(p, ctxt, creatorProp));
725	                } catch (UnresolvedForwardReference reference) {
726	                    // [databind#3030]: Handle forward reference in creator property;
727	                    //   assign null placeholder, resolve after bean construction
728	                    buffer.assignParameter(creatorProp, null);
729	                    BeanReferring referring = handleUnresolvedReference(ctxt,
730	                            creatorProp, buffer, reference);
731	                    if (referrings == null) {
732	                        referrings = new ArrayList<>();
733	                    }
734	                    referrings.add(referring);
735	                }
736	                continue;
737	            }
738	
739	            // regular property? needs buffering
740	            int ix = _propNameMatcher.matchName(propName);
741	            if (ix >= 0) {
742	                SettableBeanProperty prop = _propsByIndex[ix];
743	                // [databind#3724]: Special handling because Records' ignored creator props
744	                // weren't removed (to help in creating constructor-backed PropertyCreator)
745	                // so they ended up in _beanProperties, unlike POJO (whose ignored
746	                // props are removed)
747	                // [databind#3938]: except if it's MethodProperty
748	                if (!_beanType.isRecordType() || (prop instanceof MethodProperty)) {
749	                    // 12-Aug-2025, tatu: [databind#5237] Mergeable properties need
750	                    //    special handling: must defer deserialization until POJO
751	                    //    is constructed.
752	                    if (prop.isMerging()) {
753	                        TokenBuffer tb = ctxt.bufferForInputBuffering(p);
754	                        tb.copyCurrentStructure(p);
755	                        buffer.bufferMergingProperty(prop, tb);
756	                        continue;
757	                    }
758	                    try {
759	                        buffer.bufferProperty(prop, _deserializeWithErrorWrapping(p, ctxt, prop));
760	                    } catch (UnresolvedForwardReference reference) {
761	                        // 14-Jun-2016, tatu: As per [databind#1261], looks like we need additional
762	                        //    handling of forward references here. Not exactly sure why existing
763	                        //    facilities did not cover, but this does appear to solve the problem
764	                        BeanReferring referring = handleUnresolvedReference(ctxt,
765	                                prop, buffer, reference);
766	                        if (referrings == null) {
767	                            referrings = new ArrayList<>();
768	                        }
769	                        referrings.add(referring);
770	                    }
771	                    continue;
772	                }
773	            }
774	
775	            // "any property"?
776	            if (_anySetter != null) {
777	                try {
778	                    // [databind#4639] Since 2.18.1 AnySetter might not part of the creator, but just some field.
779	                    if (_anySetter.isFieldType() ||
780	                            // [databind#4639] 2.18.2: Also should account for setter type :-/
781	                            _anySetter.isSetterType()) {
782	                        buffer.bufferAnyProperty(_anySetter, propName, _anySetter.deserialize(p, ctxt));
783	                    } else {
784	                        buffer.bufferAnyParameterProperty(_anySetter, propName, _anySetter.deserialize(p, ctxt));
785	                    }
786	                } catch (Exception e) {
787	                    throw wrapAndThrow(e, _beanType.getRawClass(), propName, ctxt);
788	                }
789	                continue;
790	            }
791	            // 29-Mar-2021, tatu: [databind#3082] May skip collection if we know
792	            //    they'd just get ignored (note: any-setter handled above; unwrapped
793	            //    properties also separately handled)
794	            if (_ignoreAllUnknown) {
795	                // 22-Aug-2021, tatu: [databind#3252] must ensure we do skip the whole value
796	                p.skipChildren();
797	                continue;
798	            }
799	            // Ok then, let's collect the whole field; name and value
800	            if (unknown == null) {
801	                unknown = ctxt.bufferForInputBuffering(p);
802	            }
803	            unknown.writeName(propName);
804	            unknown.copyCurrentStructure(p);
805	        }
806	
807	        // We hit END_OBJECT, so:
808	        Object bean;
809	        try {
810	            bean = creator.build(ctxt, buffer);
811	        } catch (Exception e) {
812	            return wrapInstantiationProblem(ctxt, e);
813	        }
814	
815	        // [databind#1516]: Inject back references for managed reference creator properties
816	        if (creator.hasManagedReferenceProperties()) {
817	            for (SettableBeanProperty prop : creator.properties()) {
818	                if (prop instanceof ManagedReferenceProperty managedProp) {
819	                    Object value = buffer.getParameter(ctxt, prop);
820	                    if (value != null) {
821	                        managedProp.set(ctxt, bean, value);
822	                    }
823	                }
824	            }
825	        }
826	
827	        p.assignCurrentValue(bean);
828	        // [databind#4938] Since 2.19, allow returning `null` from creator,
829	        //  but if so, need to skip all possibly relevant content
830	        if (bean == null) {
831	            _handleNullFromPropsBasedCreator(null, ctxt, unknown, referrings);
832	            return null;
833	        }
834	
835	        // 13-Apr-2020, tatu: [databind#2678] need to handle injection here
836	        if (_injectables != null) {
837	            injectValues(ctxt, bean);
838	        }
839	
840	        if (referrings != null) {
841	            for (BeanReferring referring : referrings) {
842	               referring.setBean(bean);
843	            }
844	        }
845	        if (unknown != null) {
846	            // polymorphic?
847	            if (bean.getClass() != _beanType.getRawClass()) { // lgtm [java/dereferenced-value-may-be-null]
848	                return handlePolymorphic(null, ctxt, bean, unknown);
849	            }
850	            // no, just some extra unknown properties
851	            return handleUnknownProperties(ctxt, bean, unknown);
852	        }
853	        return bean;
854	    }
