907	    @Override
908	    protected Object _deserializeFromArray(JsonParser p, DeserializationContext ctxt) throws JacksonException
909	    {
910	        // note: cannot call `_delegateDeserializer()` since order reversed here:
911	        ValueDeserializer<Object> delegateDeser = _arrayDelegateDeserializer;
912	        // fallback to non-array delegate
913	        if ((delegateDeser != null) || ((delegateDeser = _delegateDeserializer) != null)) {
914	            Object bean = _valueInstantiator.createUsingArrayDelegate(ctxt,
915	                    delegateDeser.deserialize(p, ctxt));
916	            if (_injectables != null) {
917	                injectValues(ctxt, bean);
918	            }
919	            return bean;
920	        }
921	        final CoercionAction act = _findCoercionFromEmptyArray(ctxt);
922	        final boolean unwrap = ctxt.isEnabled(DeserializationFeature.UNWRAP_SINGLE_VALUE_ARRAYS);
923	
924	        if (unwrap || (act != CoercionAction.Fail)) {
925	            JsonToken unwrappedToken = p.nextToken();
926	            if (unwrappedToken == JsonToken.END_ARRAY) {
927	                switch (act) {
928	                case AsEmpty:
929	                    return getEmptyValue(ctxt);
930	                case AsNull:
931	                case TryConvert:
932	                    return getNullValue(ctxt);
933	                default:
934	                }
935	                return ctxt.handleUnexpectedToken(getValueType(ctxt), JsonToken.START_ARRAY, p, null);
936	            }
937	            if (unwrap) {
938	                // 23-Aug-2022, tatu: To prevent unbounded nested arrays, we better
939	                //   check there is NOT another START_ARRAY lurking there..
940	                if (unwrappedToken == JsonToken.START_ARRAY) {
941	                    JavaType targetType = getValueType(ctxt);
942	                    return ctxt.handleUnexpectedToken(targetType, JsonToken.START_ARRAY, p,
943	"Cannot deserialize value of type %s from deeply-nested Array: only single wrapper allowed with `%s`",
944	                            ClassUtil.getTypeDescription(targetType),
945	                                    "DeserializationFeature.UNWRAP_SINGLE_VALUE_ARRAYS");
946	                }
947	                final Object value = deserialize(p, ctxt);
948	                if (p.nextToken() != JsonToken.END_ARRAY) {
949	                    handleMissingEndArrayForSingle(p, ctxt);
950	                }
951	                return value;
952	            }
953	            // 15-Nov-2022, tatu: ... we probably should pass original `JsonToken.START_ARRAY`
954	            //     as unexpected token, since `p` now points to `unwrappedToken` instead...
955	        }
956	        return ctxt.handleUnexpectedToken(getValueType(ctxt), p);
