protected boolean isPotentialBeanType(Class<?> type)
    {
        String typeStr = ClassUtil.canBeABeanType(type);
        if (typeStr != null) {
            throw new IllegalArgumentException("Cannot deserialize Class "+type.getName()+" (of type "+typeStr+") as a Bean");
        }
        if (ClassUtil.isProxyType(type)) {
            throw new IllegalArgumentException("Cannot deserialize Proxy class "+type.getName()+" as a Bean");
        }
        // NOTE: [databind#3079]: Do NOT reject local/anonymous types here even though
        // they cannot be instantiated by Jackson, since they can still be
        // populated when using readerForUpdating (where an existing instance is provided
        // and Jackson only needs to set fields/setters, not construct).
        // Non-update deserialization will fail naturally later with a more specific
        // error about missing constructors.
        return true;
    }

